using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // [Breaking Change 1] Discriminator renamed from "Discriminator" to "$type".
            // Existing 500K docs use "Discriminator"; keep the old name so reads still work
            // and direct SQL queries (WHERE c.Discriminator = ...) remain valid.
            entity.HasDiscriminator<string>("Discriminator");

            // [Breaking Change 2] id format changed from "Product|123" to just "123".
            // Existing docs use the old composite format; preserve it.
            entity.HasDiscriminatorInJsonId();

            // [Breaking Change 3] Key property is now mapped directly to JSON "id".
            // Existing docs store Id separately; keep the EF8 shadow-id behaviour.
            entity.HasShadowId();

            // [Breaking Change 4] HasIndex now throws (Cosmos indexes all properties by default).
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

