class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we kept "Discriminator" as the property name.
        // [Breaking Change 5] EF9 adds VALUE to projections; raw SQL queries must include VALUE
        // in any scalar projections. Full-document SELECT * is unaffected.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // [Breaking Change 6] Sync I/O now throws by default — use async APIs.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

